member.example:
Bind the AudioSource volume property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceVolumeBinder _volume;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _volume;
    }


Bind the AudioSource volume property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceVolumeBinder Volume =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _volume;
    }

Switch the AudioSource volume between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceVolumeSwitcherBinder _isHighVolume;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighVolume;
    }


Switch the AudioSource volume between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _highVolume;
        
        [SerializeField] 
        private float _lowVolume;
        
        private AudioSourceVolumeSwitcherBinder IsHighVolume => new(
            _audioSource, _highVolume, _lowVolume);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighVolume;
    }
